  async function loadTrend(){const keyword=String(state.topic||els.customTopic.value||'').trim();if(keyword.length<2){toast('먼저 확인할 주제를 골라주세요.');return}if(!state.loggedIn||!state.csrfToken){toast('공식 데이터를 확인하려면 네이버 로그인이 필요해요.');return}const requestId=++state.trendRequestId;els.loadTrend.disabled=true;els.loadTrend.textContent='확인 중';try{const response=await fetch('/api/v1/naver/trend',{method:'POST',credentials:'same-origin',headers:{'content-type':'application/json','X-CSRF-Token':state.csrfToken},body:JSON.stringify({keyword})});const payload=await response.json();if(!response.ok||!payload.trend)throw new Error(payload.error||'trend_failed');if(requestId!==state.trendRequestId||keyword!==String(state.topic||els.customTopic.value||'').trim())return;const trend=payload.trend;els.trendPoints.innerHTML='';trend.points.slice(-12).forEach(point=>{const item=document.createElement('li');const bar=document.createElement('span');bar.style.height=Math.max(4,Math.min(100,Number(point.ratio)))+'px';const value=document.createElement('b');value.textContent=Number(point.ratio).toFixed(1);const date=document.createElement('small');date.textContent=String(point.period).slice(5);item.append(bar,value,date);els.trendPoints.append(item)});els.trendMeta.textContent='NAVER DataLab · '+trend.startDate+'~'+trend.endDate+' · 주간 상대값 · '+(trend.cached?'캐시 사용 · ':'')+'조회 '+new Date(trend.fetchedAt).toLocaleString('ko-KR');els.trendResult.hidden=false;setLive('실제 검색 횟수가 아닌 네이버 검색 관심도 상대 추세를 불러왔어요.')}catch{els.trendResult.hidden=false;els.trendMeta.textContent='현재 공식 데이터를 불러올 수 없어요. 추정값으로 대신 표시하지 않습니다.';els.trendPoints.innerHTML=''}finally{if(requestId===state.trendRequestId){els.loadTrend.disabled=false;els.loadTrend.textContent='상대 추세 확인'}}}
  async function refreshSearchAdsStatus(){if(location.protocol==='file:'||!state.csrfToken)return;try{const response=await fetch('/api/v1/naver/searchads/status',{credentials:'same-origin',headers:{accept:'application/json'}});const payload=await response.json();state.searchAdsEnabled=Boolean(response.ok&&payload.enabled);els.loadKeywords.hidden=!state.searchAdsEnabled;els.keywordStatus.textContent=state.searchAdsEnabled?'네이버 검색광고 API가 제공하는 월간 PC·모바일 검색수와 경쟁 참고값입니다.':'현재 배포에서는 제공하지 않습니다. 운영자의 약관 확인과 서버 설정 후에만 켜집니다.'}catch{state.searchAdsEnabled=false;els.loadKeywords.hidden=true;els.keywordStatus.textContent='현재 기능 상태를 확인할 수 없습니다.'}}
